            new() { Id = 10, Code = "PHYS 305", Title = "Quantum Mechanics", Description = "Introduction to the principles of quantum mechanics including wave functions, the Schrödinger equation, and quantum states.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Room = "Physics Lab 220", DepartmentId = 4, InstructorId = 5, IsFeatured = true },
            new() { Id = 11, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from ancient times through 1500 CE, covering major cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", Room = "Liberal Arts 115", DepartmentId = 5, InstructorId = 6 },
            new() { Id = 12, Code = "HIST 340", Title = "Medieval Europe", Description = "Detailed examination of European society, culture, and politics from the fall of Rome to the Renaissance.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Room = "Liberal Arts 220", DepartmentId = 5, InstructorId = 6 },
            new() { Id = 13, Code = "BIO 101", Title = "Introduction to Biology", Description = "Foundational course covering cell biology, genetics, evolution, and ecology. Includes laboratory work.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Life Sciences 100", DepartmentId = 6, InstructorId = 7, IsFeatured = true },
            new() { Id = 14, Code = "BIO 320", Title = "Molecular Biology", Description = "Study of biological processes at the molecular level including DNA replication, transcription, translation, and gene regulation.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Room = "Life Sciences 310", DepartmentId = 6, InstructorId = 7 },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

