@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Browse Courses — Course Catalog</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" id="search" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or keyword…" />
    </div>
    <div class="col-md-4">
        <label for="dept" class="form-label">Department</label>
        <select id="dept" name="dept" class="form-select">
            <option value="">All Departments</option>
            @foreach (var d in Catalog.GetDepartments())
            {
                if (d.Id == Dept)
                {
                    <option value="@d.Id" selected>@d.Name</option>
                }
                else
                {
                    <option value="@d.Id">@d.Name</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@{
    var results = Catalog.SearchCourses(Search, Dept);
}

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <p class="text-muted">Showing @results.Count course(s)</p>
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in results)
            {
                var dept = Catalog.GetDepartment(course.DepartmentId);
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "dept")]
    public int? Dept { get; set; }
}

@page "/courses/{id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@{
    var course = Catalog.GetCourse(Id);
}

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The course you are looking for does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    var dept = Catalog.GetDepartment(course.DepartmentId);
    var instructor = Catalog.GetInstructor(course.InstructorId);

    <PageTitle>@course.Code — Course Catalog</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            @if (dept is not null)
            {
                <li class="breadcrumb-item"><a href="departments/@dept.Id">@dept.Name</a></li>
            }
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            @if (instructor is not null)
            {
                <h4 class="mt-4">Instructor</h4>
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@instructor.Name</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@instructor.Title</h6>
                        <p class="card-text">@instructor.Bio</p>
                        <p class="card-text"><small class="text-muted">📧 @instructor.Email</small></p>
                    </div>
                </div>
            }
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><strong>Course Details</strong></div>
                <ul class="list-group list-group-flush">
                    <li class="list-group-item"><strong>Credits:</strong> @course.Credits</li>
                    <li class="list-group-item"><strong>Schedule:</strong> @course.Schedule</li>
                    <li class="list-group-item"><strong>Room:</strong> @course.Room</li>
                    @if (dept is not null)
                    {
                        <li class="list-group-item"><strong>Department:</strong> @dept.Name</li>
                    }
                </ul>
            </div>

            <a href="enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
            <a href="courses" class="btn btn-outline-secondary w-100 mt-2">Back to Courses</a>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }
}

@page "/departments"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Departments — Course Catalog</PageTitle>

<h1>Departments</h1>
<p>Explore our academic departments and the courses they offer.</p>

<div class="row">
    @foreach (var dept in Catalog.GetDepartments())
    {
        var courseCount = Catalog.GetCoursesByDepartment(dept.Id).Count;
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h4 class="card-title">@dept.Code — @dept.Name</h4>
                    <p class="card-text">@dept.Description</p>
                    <p class="text-muted">@courseCount course(s) available</p>
                </div>
                <div class="card-footer">
                    <a href="departments/@dept.Id" class="btn btn-outline-primary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@page "/departments/{id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@{
    var dept = Catalog.GetDepartment(Id);
}

@if (dept is null)
{
    <PageTitle>Department Not Found</PageTitle>
    <h1>Department Not Found</h1>
    <p>The department you are looking for does not exist.</p>
    <a href="departments" class="btn btn-primary">Back to Departments</a>
}
else
{
    var courses = Catalog.GetCoursesByDepartment(dept.Id);

    <PageTitle>@dept.Name — Course Catalog</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="departments">Departments</a></li>
            <li class="breadcrumb-item active" aria-current="page">@dept.Name</li>
        </ol>
    </nav>

    <h1>@dept.Code — @dept.Name</h1>
    <p class="lead">@dept.Description</p>

    <h3 class="mt-4">Courses</h3>

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses are currently listed for this department.</div>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int Id { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request — Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

